using BgCommon.Script.Runtime.Configuration;namespace BgCommon.Script.Runtime.Services;/// <summary>/// 遥测提供程序接口./// </summary>public interface ITelemetryProvider{    /// <summary>    /// 初始化遥测提供程序.    /// </summary>    /// <param name="version">版本信息.</param>    /// <param name="settings">应用程序设置实例.</param>    void Initialize(string version, IApplicationSettings settings);    /// <summary>    /// Gets 最近一次发生的错误.    /// </summary>    Exception? LastError { get; }    /// <summary>    /// 当最近一次错误发生变化时触发的事件.    /// </summary>    event Action LastErrorChanged;    /// <summary>    /// 清除最近一次的错误记录.    /// </summary>    void ClearLastError();    /// <summary>    /// 上报错误异常.    /// </summary>    /// <param name="exception">需要上报的异常对象接口.</param>    void ReportError(Exception exception);}